int btree_cursor_next(BTreeCursor *cur) {
cur->cell_index++;
// Case 1: more cells in current leaf
page = fetch_page(pool, cur->page_id);
cell_count = read_be16(page + 3);
unpin_page(pool, cur->page_id, false);
if (cur->cell_index < cell_count)
return 0;  // OK — same page
// Case 2: leaf exhausted — ascend via stack
while (cur->stack_depth > 0) {
cur->stack_depth--;
parent = stack[stack_depth];
parent.cell_index++;
page = fetch_page(pool, parent.page_id);
parent_cells = read_be16(page + 3);
if (parent.cell_index <= parent_cells) {
// More children — descend to next subtree
child = (parent.cell_index == parent_cells)
? read_be32(page + 8)  // right_child
: read_be32(page + cell_ptr); // left_child
// Re-push parent with updated index
stack[stack_depth++] = parent;
unpin_page(pool, parent.page_id, false);
// Descend to leftmost leaf of child
descend_to_leftmost_leaf(cur, child);
return 0;  // OK — new page
}
unpin_page(pool, parent.page_id, false);
}
// Case 3: stack empty — entire tree exhausted
cur->is_eof = true;
return 1;  // EOF
}
